def validate(args, output):
    from math import comb
    n, k = args[0], args[1]
    if not isinstance(output, list):
        return False
    seen = set()
    for combo in output:
        if not isinstance(combo, list) or len(combo) != k:
            return False
        for v in combo:
            if not isinstance(v, int) or v < 1 or v > n:
                return False
        key = tuple(sorted(combo))
        if len(set(key)) != k:
            return False
        if key in seen:
            return False
        seen.add(key)
    return len(seen) == comb(n, k)

