function validate(args, output) {
    const n = args[0], k = args[1];
    if (!Array.isArray(output)) return false;
    function comb(a, b) {
        if (b < 0 || b > a) return 0;
        b = Math.min(b, a - b);
        let r = 1;
        for (let i = 0; i < b; i++) r = r * (a - i) / (i + 1);
        return Math.round(r);
    }
    const seen = new Set();
    for (const combo of output) {
        if (!Array.isArray(combo) || combo.length !== k) return false;
        for (const v of combo) {
            if (!Number.isInteger(v) || v < 1 || v > n) return false;
        }
        const sorted = combo.slice().sort((a, b) => a - b);
        if (new Set(sorted).size !== k) return false;
        const key = sorted.join(',');
        if (seen.has(key)) return false;
        seen.add(key);
    }
    return seen.size === comb(n, k);
}

