class Solution:
    def combine(self, n, k):
        res = []
        path = []
        def bt(start):
            if len(path) == k:
                res.append(path[:])
                return
            for v in range(start, n + 1):
                if n - v + 1 < k - len(path):
                    break
                path.append(v)
                bt(v + 1)
                path.pop()
        bt(1)
        res.sort()
        return res

