var combine = function(n, k) {
    const res = [];
    const path = [];
    function bt(start) {
        if (path.length === k) {
            res.push(path.slice());
            return;
        }
        for (let v = start; v <= n; v++) {
            if (n - v + 1 < k - path.length) break;
            path.push(v);
            bt(v + 1);
            path.pop();
        }
    }
    bt(1);
    res.sort((a, b) => {
        const m = Math.min(a.length, b.length);
        for (let i = 0; i < m; i++) if (a[i] !== b[i]) return a[i] - b[i];
        return a.length - b.length;
    });
    return res;
};
